// 方法1: サイズ指定で作成（デフォルト値で初期化）
int[] scores = new int[5];
// → [0, 0, 0, 0, 0]  ※intのデフォルト値は0

// 方法2: 初期値を指定して作成
String[] fruits = {"りんご", "みかん", "ぶどう"};

// 方法3: newキーワード + 初期値
double[] prices = new double[]{100.0, 250.5, 380.0};

// 各型のデフォルト値
// int    → 0
// double → 0.0
// boolean → false
// char   → '\u0000'
// String(参照型) → null

int[] nums = {10, 20, 30, 40, 50};

// 要素の取得（0始まり）
System.out.println(nums[0]); // 10（最初の要素）
System.out.println(nums[4]); // 50（最後の要素）

// 要素の変更
nums[2] = 99;
System.out.println(nums[2]); // 99

// 配列の長さ
System.out.println(nums.length); // 5 ※()は不要

// 最後の要素を取得
System.out.println(nums[nums.length - 1]); // 50

// 範囲外アクセス → ArrayIndexOutOfBoundsException
// System.out.println(nums[5]); // 実行時エラー！

String[] names = {"太郎", "花子", "次郎"};

// 通常のfor文
for (int i = 0; i < names.length; i++) {
    System.out.println((i + 1) + "番: " + names[i]);
}
// 1番: 太郎  2番: 花子  3番: 次郎

// 拡張for文（for-each）- 全要素を順に処理
for (String name : names) {
    System.out.println("こんにちは、" + name + "さん");
}

// 合計・平均の計算
int[] scores = {85, 92, 78, 95, 88};
int sum = 0;
for (int score : scores) {
    sum += score;
}
double avg = (double) sum / scores.length;
System.out.println("平均: " + avg); // 平均: 87.6

