// 二次元配列の宣言と初期化
int[][] matrix = {
    {1, 2, 3},   // 0行目
    {4, 5, 6},   // 1行目
    {7, 8, 9}    // 2行目
};

// 要素アクセス: matrix[行][列]
System.out.println(matrix[0][0]); // 1（0行0列）
System.out.println(matrix[1][2]); // 6（1行2列）
System.out.println(matrix[2][1]); // 8（2行1列）

// 行数と列数
System.out.println(matrix.length);    // 3（行数）
System.out.println(matrix[0].length); // 3（0行目の列数）

// 全要素の走査（二重ループ）
for (int i = 0; i < matrix.length; i++) {
    for (int j = 0; j < matrix[i].length; j++) {
        System.out.print(matrix[i][j] + " ");
    }
    System.out.println();
}

import java.util.Arrays;

int[] nums = {5, 2, 8, 1, 9, 3};

// ソート（昇順）
Arrays.sort(nums);
System.out.println(Arrays.toString(nums));
// [1, 2, 3, 5, 8, 9]

// 文字列表現
String[] fruits = {"りんご", "みかん", "ぶどう"};
System.out.println(Arrays.toString(fruits));
// [りんご, みかん, ぶどう]

// 配列のコピー
int[] original = {10, 20, 30};
int[] copy = Arrays.copyOf(original, 5);
System.out.println(Arrays.toString(copy));
// [10, 20, 30, 0, 0]  ※拡大時は0で埋まる

// 範囲コピー
int[] sub = Arrays.copyOfRange(original, 0, 2);
System.out.println(Arrays.toString(sub)); // [10, 20]

// 全要素を指定値で埋める
int[] filled = new int[5];
Arrays.fill(filled, 99);
System.out.println(Arrays.toString(filled));
// [99, 99, 99, 99, 99]

// 配列の比較
int[] a = {1, 2, 3};
int[] b = {1, 2, 3};
System.out.println(a == b);             // false（参照比較）
System.out.println(Arrays.equals(a, b)); // true（内容比較）

import java.util.Arrays;

// 二分探索（配列がソート済みであること！）
int[] sorted = {10, 20, 30, 40, 50};
int idx = Arrays.binarySearch(sorted, 30);
System.out.println(idx); // 2（インデックス）

int notFound = Arrays.binarySearch(sorted, 25);
System.out.println(notFound); // 負の値（見つからない）

// 部分ソート（fromIndex, toIndex）
int[] data = {5, 3, 8, 1, 9, 2};
Arrays.sort(data, 1, 4); // index 1〜3をソート
System.out.println(Arrays.toString(data));
// [5, 1, 3, 8, 9, 2] ※index 1-3のみソート

// 二次元配列の文字列表現
int[][] m = {{1, 2}, {3, 4}};
System.out.println(Arrays.deepToString(m));
// [[1, 2], [3, 4]]

// 二次元配列の比較
int[][] m2 = {{1, 2}, {3, 4}};
System.out.println(Arrays.deepEquals(m, m2)); // true

