import java.util.ArrayList;
import java.util.List;

List<String> fruits = new ArrayList<>();

// 追加
fruits.add("りんご");           // 末尾に追加
fruits.add("みかん");
fruits.add("ぶどう");
fruits.add(1, "バナナ");         // index1に挿入
