import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

// ArrayList: 内部に配列 → ランダムアクセスが高速
List<String> arrayList = new ArrayList<>();
arrayList.add("A");
arrayList.add("B");
arrayList.add("C");
String b = arrayList.get(1); // O(1) 高速！

// LinkedList: ノードの連結 → 先頭・途中の挿入・削除が高速
List<String> linkedList = new LinkedList<>();
linkedList.add("X");
linkedList.add("Y");
linkedList.add("Z");
linkedList.add(0, "W"); // O(1) 先頭挿入が高速！

// 使い分けの目安:
// ・ランダムアクセスが多い → ArrayList（大半のケース）
// ・先頭への追加・削除が頻繁 → LinkedList
// ・迷ったらArrayListを選ぶ

