import java.util.HashSet;
import java.util.Set;

Set<String> colors = new HashSet<>();

// 追加
colors.add("赤");
colors.add("青");
colors.add("緑");
colors.add("赤"); // 重複は無視される

System.out.println(colors.size());  // 3（重複は1つ）
System.out.println(colors);         // [赤, 青, 緑]（順序不定）

// 存在チェック
System.out.println(colors.contains("青")); // true

// 削除
colors.remove("緑");

// ループ
for (String c : colors) {
    System.out.println(c);
}

// Listから重複を除去するテクニック
List<String> list = List.of("A", "B", "A", "C", "B");
Set<String> unique = new HashSet<>(list);
System.out.println(unique); // [A, B, C]

import java.util.*;

// TreeSet: 要素がソートされる（自然順序）
Set<Integer> treeSet = new TreeSet<>();
treeSet.add(30);
treeSet.add(10);
treeSet.add(20);
System.out.println(treeSet); // [10, 20, 30] 常にソート順

// LinkedHashSet: 挿入順序を保持
Set<String> linked = new LinkedHashSet<>();
linked.add("C");
linked.add("A");
linked.add("B");
System.out.println(linked); // [C, A, B] 挿入順を維持

// 使い分け:
// HashSet     → 最速。順序不要の場合（大半のケース）
// TreeSet     → ソート順が必要な場合
// LinkedHashSet → 挿入順を保持したい場合

// 集合演算
Set<String> set1 = new HashSet<>(Set.of("A", "B", "C"));
Set<String> set2 = new HashSet<>(Set.of("B", "C", "D"));

// 積集合（共通要素）
set1.retainAll(set2);
System.out.println(set1); // [B, C]

