import java.util.HashMap;
import java.util.Map;

Map<String, Integer> scores = new HashMap<>();

// 値の追加・更新
scores.put("太郎", 85);
scores.put("花子", 92);
scores.put("次郎", 78);
scores.put("太郎", 90);  // 同じキーは上書き

// 値の取得
int taro = scores.get("太郎");  // 90
System.out.println(scores.get("四郎")); // null（存在しない）

// デフォルト値付き取得
int value = scores.getOrDefault("四郎", 0); // 0

// 存在チェック
System.out.println(scores.containsKey("花子")); // true
System.out.println(scores.containsValue(92));   // true

// サイズ
System.out.println(scores.size()); // 3

// 削除
scores.remove("次郎");

// ループ（エントリーセット）
for (Map.Entry<String, Integer> e : scores.entrySet()) {
    System.out.println(e.getKey() + ": " + e.getValue());
}

import java.util.*;

Map<String, Integer> map = new HashMap<>();
map.put("A", 1);
map.put("B", 2);

// putIfAbsent: キーが存在しない場合のみ追加
map.putIfAbsent("A", 99); // "A"は既にあるので変更なし
map.putIfAbsent("C", 3);  // "C"を追加

// merge: 既存値と新値を結合
map.merge("A", 10, Integer::sum); // A: 1 + 10 = 11

// forEach
map.forEach((k, v) -> System.out.println(k + "=" + v));

// キーセット・値コレクション
Set<String> keys = map.keySet();      // [A, B, C]
Collection<Integer> vals = map.values(); // [11, 2, 3]

// TreeMap: キーがソートされる
Map<String, Integer> treeMap = new TreeMap<>();
treeMap.put("banana", 200);
treeMap.put("apple", 100);
treeMap.put("cherry", 300);
System.out.println(treeMap);
// {apple=100, banana=200, cherry=300} キーでソート

