import java.util.*;

// --- 配列 → List ---
String[] array = {"A", "B", "C"};

// Arrays.asList: 固定サイズのList（追加・削除不可）
List<String> fixed = Arrays.asList(array);
// fixed.add("D"); // UnsupportedOperationException
fixed.set(0, "X"); // OK（変更は可能）

// 可変Listに変換（推奨）
List<String> mutable = new ArrayList<>(Arrays.asList(array));
mutable.add("D"); // OK

// Java 11+: List.of() で不変List
List<String> immutable = List.of(array);

// --- List → 配列 ---
List<String> list = List.of("X", "Y", "Z");

// toArray（型指定）
String[] arr = list.toArray(new String[0]);
System.out.println(Arrays.toString(arr)); // [X, Y, Z]

// Java 11+ toArray（メソッド参照）
String[] arr2 = list.toArray(String[]::new);

// オートボクシング: プリミティブ → ラッパー（自動変換）
Integer a = 100;         // int → Integer（自動）
Double b = 3.14;         // double → Double（自動）

// アンボクシング: ラッパー → プリミティブ（自動変換）
int c = a;               // Integer → int（自動）
double d = b;            // Double → double（自動）

// コレクションでの利用
List<Integer> numbers = new ArrayList<>();
numbers.add(10);         // int → Integer（オートボクシング）
numbers.add(20);
int first = numbers.get(0); // Integer → int（アンボクシング）

// 計算も自動変換
Integer x = 10;
Integer y = 20;
int sum = x + y; // Integer → int → 計算 → int

// ⚠️ nullのアンボクシングに注意！
Integer nullVal = null;
// int n = nullVal; // NullPointerException!

// 文字列 → 数値変換（parseXxx）
int i = Integer.parseInt("123");         // 123
double d = Double.parseDouble("3.14");   // 3.14
long l = Long.parseLong("1000000");      // 1000000

// 数値 → 文字列変換
String s1 = Integer.toString(123);         // "123"
String s2 = String.valueOf(123);           // "123"（推奨）

// 定数
System.out.println(Integer.MAX_VALUE);     // 2147483647
System.out.println(Integer.MIN_VALUE);     // -2147483648
System.out.println(Double.MAX_VALUE);      // 1.7976931348623157E308

// valueOf: キャッシュ付きオブジェクト生成
Integer a1 = Integer.valueOf(127);
Integer a2 = Integer.valueOf(127);
System.out.println(a1 == a2);  // true（-128〜127はキャッシュ）

Integer b1 = Integer.valueOf(128);
